answer:
三者的核心区别：

| 函数 | 功能 | 是否初始化 | 原型 |
|------|------|-----------|------|
| `malloc` | 分配指定字节数 | 否（内容不确定） | `void *malloc(size_t size)` |
| `calloc` | 分配并清零 | 是（全部置0） | `void *calloc(size_t nmemb, size_t size)` |
| `realloc` | 调整已分配内存大小 | 新增部分不初始化 | `void *realloc(void *ptr, size_t size)` |

**使用场景：**

```c
// malloc：通用分配，最常用
int *arr = malloc(10 * sizeof(int));  // 10个int，内容随机

// calloc：需要零初始化时
int *counts = calloc(256, sizeof(int));  // 256个int，全部为0
// 等价于：malloc + memset(arr, 0, n * sizeof(int))

// realloc：动态扩容/缩容
int *bigger = realloc(arr, 20 * sizeof(int));  // 扩到20个
```

**realloc 的常见坑：**

**坑1：直接用原指针接收返回值**
```c
// 错误！如果 realloc 失败返回 NULL，原指针丢失，内存泄漏
ptr = realloc(ptr, new_size);

// 正确：用临时指针
void *tmp = realloc(ptr, new_size);
if (tmp == NULL) {
    // ptr 仍然有效，可以继续使用或 free
    free(ptr);
    exit(1);
}
ptr = tmp;
```

**坑2：realloc 可能移动内存**
```c
int *old = ptr;
ptr = realloc(ptr, new_size);
// 如果 ptr != old，旧地址已失效
// 所有指向旧内存的其他指针都变成悬垂指针！
```

**坑3：realloc(NULL, size) 等价于 malloc(size)**
```c
int *p = NULL;
p = realloc(p, 100);  // 合法，等价于 malloc(100)
```
这个特性可以简化动态数组的初始化代码。

**坑4：realloc(ptr, 0) 的行为**
在C11标准中，`realloc(ptr, 0)` 的行为是实现定义的（可能返回NULL或特殊指针），不建议使用。要释放内存就用 `free(ptr)`。

**最佳实践：**
- 需要0初始化用 `calloc`，否则用 `malloc`（更快）
- `realloc` 永远用临时指针接收
- 分配后立即检查返回值是否为 `NULL`
- 用 `sizeof(*ptr)` 代替 `sizeof(type)` 更安全：
  ```c
  int *arr = malloc(10 * sizeof(*arr));  // 即使 arr 类型改了也不怕
  ```

```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    char *data;
    int top;
    int capacity;
} Stack;

Stack stack_new(int capacity) {
    Stack s;
    s.data = malloc(capacity * sizeof(char));
    s.top = -1;
    s.capacity = capacity;
    return s;
}

int stack_push(Stack *s, char c) {
    if (s->top + 1 >= s->capacity) return 0;
    s->data[++s->top] = c;
    return 1;
}

int stack_pop(Stack *s, char *out) {
    if (s->top < 0) return 0;
    *out = s->data[s->top--];
    return 1;
}

int stack_is_empty(Stack *s) {
    return s->top < 0;
}

char stack_peek(Stack *s) {
    return s->top >= 0 ? s->data[s->top] : '\0';
}

void stack_free(Stack *s) {
    free(s->data);
    s->top = -1;
    s->capacity = 0;
}

int is_matching(char open, char close) {
    return (open == '(' && close == ')') ||
           (open == '[' && close == ']') ||
           (open == '{' && close == '}');
}

int check_brackets(const char *str) {
    int len = strlen(str);
    Stack s = stack_new(len);

    for (int i = 0; str[i]; i++) {
        char c = str[i];
        if (c == '(' || c == '[' || c == '{') {
            stack_push(&s, c);
        } else if (c == ')' || c == ']' || c == '}') {
            if (stack_is_empty(&s) || !is_matching(stack_peek(&s), c)) {
                stack_free(&s);
                return 0;
            }
            char dummy;
            stack_pop(&s, &dummy);
        }
    }
    int result = stack_is_empty(&s);
    stack_free(&s);
    return result;
}

int main(void) {
    const char *tests[] = {
        "({[]})",
        "({[)]",
        "((()))",
        "(()",
        ")(",
        ""
    };
    for (int i = 0; i < 6; i++) {
        printf("%s -> %s\n", tests[i],
               check_brackets(tests[i]) ? "匹配" : "不匹配");
    }
    return 0;
}
```

**算法思路：**
1. 遇到左括号 → 入栈
2. 遇到右括号 → 检查栈顶是否是对应的左括号，是则弹出，否则不匹配
3. 字符串结束后 → 栈为空则匹配，否则有未闭合的左括号

**三种不匹配的情况：**
- `({[)]` → 右括号和栈顶不匹配
- `(()` → 字符串结束但栈不为空
- `)(` → 栈为空时遇到右括号

**栈的实现选择：**
- 数组实现：简单高效，适合已知最大容量的场景
- 链表实现：容量无上限，但每次操作有 `malloc` 开销

括号匹配是栈最经典的应用，类似的还有表达式求值、函数调用栈、深度优先搜索等。

函数指针是指向函数的指针变量，最核心的用途是**回调机制**——让调用者决定被调用的函数。

**基本语法：**
```c
// 声明函数指针
int (*compare)(const void *, const void *);

// 赋值
compare = &my_compare;  // 或直接 compare = my_compare;

// 调用
int result = compare(a, b);  // 或 (*compare)(a, b);
```

**实际应用：通用排序函数**

```c
#include <stdio.h>
#include <string.h>

typedef struct {
    char name[32];
    int age;
    float score;
} Student;

int cmp_by_age(const void *a, const void *b) {
    const Student *sa = a, *sb = b;
    return sa->age - sb->age;
}

int cmp_by_score(const void *a, const void *b) {
    const Student *sa = a, *sb = b;
    if (sa->score > sb->score) return -1;
    if (sa->score < sb->score) return 1;
    return 0;
}

int cmp_by_name(const void *a, const void *b) {
    const Student *sa = a, *sb = b;
    return strcmp(sa->name, sb->name);
}

void sort_students(Student *arr, int n, int (*cmp)(const void *, const void *)) {
    for (int i = 0; i < n - 1; i++) {
        for (int j = 0; j < n - 1 - i; j++) {
            if (cmp(&arr[j], &arr[j+1]) > 0) {
                Student tmp = arr[j];
                arr[j] = arr[j+1];
                arr[j+1] = tmp;
            }
        }
    }
}

int main(void) {
    Student students[] = {
        {"Alice", 20, 88.5},
        {"Bob", 19, 92.0},
        {"Charlie", 21, 85.0}
    };
    int n = 3;

    sort_students(students, n, cmp_by_age);
    printf("By age: "); for (int i=0;i<n;i++) printf("%s(%d) ", students[i].name, students[i].age);
    printf("\n");

    sort_students(students, n, cmp_by_score);
    printf("By score: "); for (int i=0;i<n;i++) printf("%s(%.1f) ", students[i].name, students[i].score);
    printf("\n");

    return 0;
}
```

