scanf("%d", &age);     // 输入 "25\n"，\n 留在缓冲区
scanf("%31s", name);   // 直接读到 \n，name 为空！
```
修复：在格式字符串中加空格跳过空白
```c
scanf("%d", &age);
scanf(" %31s", name);  // 注意 % 前的空格，跳过所有空白字符
```

**陷阱3：%s 遇到空格就停止**
```c
char name[64];
scanf("%63s", name);  // 输入 "Hello World"，name 只有 "Hello"
```

**推荐的安全输入方案：**

**方案一：用 fgets + sscanf（最推荐）**
```c
char line[256];
int age;
char name[64];

fgets(line, sizeof(line), stdin);
sscanf(line, "%d", &age);

fgets(line, sizeof(line), stdin);
sscanf(line, "%63s", name);
```
`fgets` 整行读取（包括换行符），不会溢出，然后从行缓冲区中解析。输入和解析分离，更安全可控。

**方案二：读取整行文本（含空格）**
```c
char sentence[256];
fgets(sentence, sizeof(sentence), stdin);

// 去掉末尾的换行符
size_t len = strlen(sentence);
if (len > 0 && sentence[len - 1] == '\n') {
    sentence[len - 1] = '\0';
}
```

**方案三：安全的自定义读取函数**
```c
int read_line(char *buf, size_t size) {
    if (fgets(buf, size, stdin) == NULL) return 0;
    size_t len = strlen(buf);
    if (len > 0 && buf[len - 1] == '\n') {
        buf[len - 1] = '\0';
        return len - 1;
    }
    // 输入太长，清空缓冲区剩余内容
    int c;
    while ((c = getchar()) != '\n' && c != EOF);
    return len;
}
```

**scanf 的安全使用清单：**
- 字符串：始终指定宽度 `%Ns`（N = 缓冲区大小 - 1）
- 数字：`%d` 之前加空格跳过空白
- 检查返回值：`if (scanf("%d", &n) != 1) { /* 处理错误 */ }`
- 混合输入：优先用 `fgets` + `sscanf`
- 永远不要用 `gets()`，它在C11中已被删除

**核心原则：** `fgets` 是C语言中最安全的输入函数，应该作为首选。`scanf` 只适合简单、格式固定的输入场景。

实现二维动态数组有三种方式，从简单到高效：

**方式一：指针数组（你用的方式）**
```c
int **create_matrix_1(int rows, int cols) {
    int **m = malloc(rows * sizeof(int *));
    for (int i = 0; i < rows; i++) {
        m[i] = malloc(cols * sizeof(int));
    }
    return m;
}

void free_matrix_1(int **m, int rows) {
    for (int i = 0; i < rows; i++) free(m[i]);
    free(m);
}
```
- 优点：可以用 `m[i][j]` 访问
- 缺点：每行单独分配，内存不连续，缓存不友好；需要多次 malloc/free

**方式二：一次分配 + 指针数组（推荐）**
```c
int **create_matrix_2(int rows, int cols) {
    int **m = malloc(rows * sizeof(int *));
    int *data = malloc(rows * cols * sizeof(int));
    for (int i = 0; i < rows; i++) {
        m[i] = data + i * cols;
    }
    return m;
}

void free_matrix_2(int **m) {
    free(m[0]);  // 释放数据区
    free(m);     // 释放指针数组
}
```
- 优点：数据连续（缓存友好），只需2次 malloc
- 优点：仍可用 `m[i][j]` 访问
- 缺点：释放时注意顺序

**方式三：一维数组模拟（最高效）**
```c
int *create_matrix_3(int rows, int cols) {
    return malloc(rows * cols * sizeof(int));
}

// 访问元素
#define MAT(m, cols, i, j) ((m)[(i) * (cols) + (j)])

void use_matrix(void) {
    int rows = 4, cols = 5;
    int *m = create_matrix_3(rows, cols);

    MAT(m, cols, 2, 3) = 42;
    printf("%d\n", MAT(m, cols, 2, 3));

    free(m);
}
```
- 优点：只需1次 malloc，内存最紧凑
- 缺点：不能用 `m[i][j]`，需要宏或函数计算索引

**三种方式对比：**

| 特性 | 方式一 | 方式二 | 方式三 |
|------|--------|--------|--------|
| malloc次数 | rows+1 | 2 | 1 |
| 内存连续 | 否 | 是 | 是 |
| m[i][j]访问 | 是 | 是 | 否 |
| 缓存友好 | 差 | 好 | 好 |
| 释放复杂度 | O(rows) | O(1) | O(1) |

**推荐：** 日常使用选方式二（兼顾可读性和性能），性能敏感场景选方式三。方式一仅适合每行长度不同的情况（不规则二维数组）。

内存池的核心思路：**预先分配一大块内存，自己管理分配和回收，避免反复调用 malloc/free。**

**固定大小内存池实现（空闲链表法）：**

```c
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>

typedef struct {
    uint8_t *buffer;
    size_t block_size;
    size_t total_blocks;
    size_t free_blocks;
    void *free_list;
} MemPool;

MemPool pool_create(size_t block_size, size_t block_count) {
    MemPool pool;
    pool.block_size = block_size < sizeof(void *) ? sizeof(void *) : block_size;
    pool.total_blocks = block_count;
    pool.free_blocks = block_count;
    pool.buffer = malloc(pool.block_size * block_count);

    pool.free_list = pool.buffer;
    uint8_t *block = pool.buffer;
    for (size_t i = 0; i < block_count - 1; i++) {
        void **next = (void **)block;
        *next = block + pool.block_size;
        block += pool.block_size;
    }
    void **last = (void **)block;
    *last = NULL;

    return pool;
}

void *pool_alloc(MemPool *pool) {
    if (pool->free_blocks == 0) return NULL;
    void *block = pool->free_list;
    pool->free_list = *(void **)block;
    pool->free_blocks--;
    return block;
}

void pool_free(MemPool *pool, void *block) {
    if (block == NULL) return;
    *(void **)block = pool->free_list;
    pool->free_list = block;
    pool->free_blocks++;
}

void pool_destroy(MemPool *pool) {
    free(pool->buffer);
    pool->buffer = NULL;
    pool->free_list = NULL;
    pool->free_blocks = 0;
}

// --- 使用示例 ---
typedef struct {
    int id;
    double value;
} Node;

int main(void) {
    MemPool pool = pool_create(sizeof(Node), 1000);

    Node *nodes[100];
    for (int i = 0; i < 100; i++) {
        nodes[i] = pool_alloc(&pool);
        nodes[i]->id = i;
        nodes[i]->value = i * 3.14;
    }

    printf("Free blocks: %zu\n", pool.free_blocks);  // 900

    for (int i = 0; i < 50; i++) {
        pool_free(&pool, nodes[i]);
    }

    printf("Free blocks: %zu\n", pool.free_blocks);  // 950

    pool_destroy(&pool);
    return 0;
}
```

**工作原理：**
1. **初始化**：分配一大块连续内存，将每个块通过内置链表串起来（利用空闲块自身存储next指针）
2. **分配**：从空闲链表头部取一个块，O(1)
3. **释放**：将块插回空闲链表头部，O(1)
4. **销毁**：一次性释放整块内存

**关键设计决策：**
- `block_size` 最小为 `sizeof(void*)`：因为空闲块需要存储 next 指针
- 利用空闲块自身存链表指针：零额外内存开销
- 分配和释放都是 O(1)：比 malloc/free 快得多

**内存池的局限性：**
- 只能分配固定大小的块
- 不能单独释放整个池的一部分内存还给系统
- 需要预估最大块数

**适用场景：**
- 频繁创建/销毁相同类型对象（如链表节点、游戏中的子弹）
- 嵌入式系统（避免内存碎片）
- 实时系统（分配时间是确定的 O(1)）

**进阶：** 可以实现多大小类的内存池（类似 slab 分配器），或支持变长分配的内存池。

question:
以下代码编译时报错 "conflicting types for 'foo'"，但我明明只定义了一次 foo 函数。这是怎么回事？

```c
#include <stdio.h>

int main(void) {
    int result = foo(3);
    printf("%d\n", result);
    return 0;
}

double foo(int x) {
    return x * 2.5;
}
```

answer:
这是因为**隐式函数声明**和**实际定义**之间的类型冲突。

当编译器遇到 `foo(3)` 时，`foo` 还没有被声明或定义。C89允许编译器假设一个未声明的函数返回 `int`，这叫隐式声明。所以编译器假设 `foo` 的类型是 `int foo(...)`。

但后面 `foo` 的实际定义是 `double foo(int x)`，返回类型从 `int` 变成了 `double`，与之前的隐式声明冲突。

**修复方案一：在使用前声明函数（推荐）**
```c
#include <stdio.h>

double foo(int x);  // 前向声明（函数原型）

int main(void) {
    int result = foo(3);
    printf("%d\n", result);
    return 0;
}

double foo(int x) {
    return x * 2.5;
}
```

**修复方案二：调整函数定义的顺序**
```c
#include <stdio.h>

double foo(int x) {
    return x * 2.5;
}

int main(void) {
    int result = foo(3);
    printf("%d\n", result);
    return 0;
}
```

**注意：** C99及以后的标准已禁止隐式函数声明。如果用 `-std=c99` 或更高标准编译，会直接报错而非警告。建议始终使用 `-std=c11 -Wall -Werror`。

**最佳实践：**
1. 每个函数都在头文件中声明，使用前 `#include` 对应头文件
2. 不依赖函数定义的顺序
3. 编译时开启 `-Wall`，隐式声明会被警告
4. `main` 函数调用其他函数时，确保所有函数在使用前都有声明

C语言字符串操作的性能优化可以从以下几个层面入手：

**1. 减少不必要的 strlen 调用**
```c
// 差：每次循环都调用 strlen
for (size_t i = 0; i < strlen(s); i++) { ... }
// strlen 是 O(n)，整个循环变成 O(n²)

// 好：缓存长度
size_t len = strlen(s);
for (size_t i = 0; i < len; i++) { ... }
```

**2. 避免反复拼接（Schlemiel the Painter 问题）**
```c
// 差：每次 strcat 都从头扫描找 '\0'
char buf[1024] = "";
strcat(buf, "Hello, ");   // 扫描 0 字节
strcat(buf, name);        // 扫描 7 字节
strcat(buf, "! ");        // 扫描 7+len 字节
strcat(buf, message);     // 扫描更远...

// 好：追踪末尾位置
char buf[1024];
size_t pos = 0;
pos += snprintf(buf + pos, sizeof(buf) - pos, "Hello, ");
pos += snprintf(buf + pos, sizeof(buf) - pos, "%s", name);
pos += snprintf(buf + pos, sizeof(buf) - pos, "! ");
pos += snprintf(buf + pos, sizeof(buf) - pos, "%s", message);
```

**3. 用 memcpy 代替 strcpy（已知长度时）**
```c
// strcpy 需要逐字节检查 '\0'
strcpy(dst, src);

// memcpy 直接按长度复制，更快
size_t len = strlen(src);
memcpy(dst, src, len + 1);
```

**4. 字符查找用 strchr/memchr 代替手写循环**
```c
// 手写循环
char *find(char *s, char c) {
    while (*s) { if (*s == c) return s; s++; }
    return NULL;
}

// 库函数通常有汇编优化
char *p = strchr(str, ',');
```

**5. 批量操作用 mem 系列函数**
```c
memset(buf, 0, sizeof(buf));    // 比 for 循环清零快
memcmp(a, b, n);                 // 比 for 循环比较快
memmove(dst, src, n);            // 比 for 循环复制快
```
`mem` 系列函数操作字节不关心 `\0`，且通常有 SIMD 优化。

**6. 字符串结构体：缓存长度**
```c
typedef struct {
    char *data;
    size_t len;
    size_t capacity;
} String;

String str_new(const char *init) {
    String s;
    s.len = strlen(init);
    s.capacity = s.len * 2;
    s.data = malloc(s.capacity + 1);
    memcpy(s.data, init, s.len + 1);
    return s;
}
```
缓存了长度后，获取长度是 O(1)，拼接时直接在末尾写入，不需要扫描。

**7. 避免频繁的 malloc/realloc**
```c
// 差：每次拼接都 realloc
// 好：预留足够空间（类似 C++ string 的策略）
void str_ensure_capacity(String *s, size_t needed) {
    if (needed <= s->capacity) return;
    size_t new_cap = s->capacity * 2;
    if (new_cap < needed) new_cap = needed;
    s->data = realloc(s->data, new_cap + 1);
    s->capacity = new_cap;
}
```

**总结：**
- C字符串的 `\0` 结尾设计导致很多操作必须线性扫描，这是性能瓶颈的根源
- 缓存长度 + 预分配空间是最有效的优化手段
- 优先使用 `mem*` 系列函数，它们通常有编译器/硬件级别的优化
- `snprintf` 比 `strcat` 更安全也更灵活
